const allItems = $input.all();
const chunks = allItems.map(item => ({
  content: item.json.content,
  priority_rank: item.json.priority_rank,
  source: item.json.source
}));

const first = allItems[0].json;
const customerName  = first.customer_name  || 'Customer';
const customerEmail = first.customer_email || '';
const emailSubject  = first.email_subject  || '';
const emailBody     = first.email_body     || '';

const tier1 = chunks.filter(c => c.priority_rank === 1);
const tier2 = chunks.filter(c => c.priority_rank === 2 && c.source !== 'gap_resolution');
const tier3 = chunks.filter(c => c.priority_rank === 3);
const gaps  = chunks.filter(c => c.source === 'gap_resolution');

const sep = '='.repeat(60);

let sp = 'You are the AI customer service assistant for Boldr Supply Co., a premium Singapore-based titanium watch micro-brand.\n\n';
sp += 'YOUR TASK: Analyse the customer email and return a single JSON object (no other text, no markdown).\n\n';
sp += 'RULES:\n';
sp += '1. PRICING: Always use Tier 1 (Rate Cards) for all prices. Never use the SOP — it has outdated prices.\n';
sp += '2. HONESTY: If the answer is not in the KB, set answerable: false. Do NOT guess. Return gap_summary.\n';
sp += '3. ORDER QUERIES: If the email is about an order (tracking, refund, cancellation, wrong item, address change), set question_type to order_status immediately. Set answerable: false and draft_reply: null.\n';
sp += '4. DRAFT REPLIES: Friendly, direct, premium brand voice. Open with: Hi [Name], thanks for reaching out!\n';
sp += '5. ESCALATION: Flag requires_escalation: true for MRI/magnetic safety, shock ratings, discontinued models, bulk orders 5+, angry customers, logo engraving.\n\n';
sp += sep + '\nTIER 1 — RATE CARDS — AUTHORITATIVE PRICING\nUse for ALL price and turnaround queries. Overrides FAQ and SOP.\n' + sep + '\n';
sp += tier1.map(c => c.content).join('\n\n') + '\n\n';
sp += sep + '\nTIER 2 — FAQ AND PRODUCT REFERENCE\nUse for specifications, materials, compatibility, Q&A.\n' + sep + '\n';
sp += tier2.map(c => c.content).join('\n\n') + '\n\n';
sp += sep + '\nTIER 3 — BRAND VOICE AND PROCESS (no prices)\n' + sep + '\n';
sp += tier3.map(c => c.content).join('\n\n');

if (gaps.length > 0) {
  sp += '\n\n' + sep + '\nAPPROVED KB ENTRIES FROM GAP RESOLUTION (treat as Tier 2)\n' + sep + '\n';
  sp += gaps.map(c => c.content).join('\n\n');
}

const schema = {
  question_type: 'engraving|servicing|materials_safety|strap_compatibility|product_general|order_status|knowledge_gap',
  intent_summary: 'one sentence',
  answerable: true,
  confidence: 'high|medium|low',
  raw_persona_tag: 'health_conscious|gifter|enthusiast|niche_buyer|prospect|owner_aftercare|transactional',
  competition_persona_tag: 'Health-Conscious Buyer|Gifter|Enthusiast/Collector|Active/Outdoor Buyer|Sustainability Advocate|null',
  theme: 'materials|sustainability|sizing|gifting|servicing|order|product_specs|other',
  marketing_signal: false,
  marketing_signal_reason: null,
  kb_sources_used: [],
  requires_escalation: false,
  escalation_reason: null,
  draft_reply: 'Hi [Name], thanks for reaching out! ...',
  gap_summary: null
};

sp += '\n\nRETURN THIS JSON SCHEMA EXACTLY (no other text):\n' + JSON.stringify(schema, null, 2);

return [{ json: {
  system_prompt: sp,
  chunk_count: chunks.length,
  customer_name: customerName,
  customer_email: customerEmail,
  email_subject: emailSubject,
  email_body: emailBody
} }];

const item = $input.first().json;

const baseFields = {
  customer_email: item.customer_email || '',
  customer_name:  item.customer_name  || 'Customer',
  email_subject:  item.email_subject  || '',
  email_body:     item.email_body     || '',
  received_at:    new Date().toISOString(),
  ticket_id:      'TKT-' + Date.now()
};

if (!item.content || !Array.isArray(item.content) || item.content.length === 0) {
  return [{ json: Object.assign({
    question_type: 'knowledge_gap',
    answerable: false,
    confidence: 'low',
    raw_persona_tag: 'niche_buyer',
    competition_persona_tag: null,
    theme: 'other',
    marketing_signal: false,
    marketing_signal_reason: null,
    kb_sources_used: [],
    requires_escalation: true,
    escalation_reason: 'Claude API returned no content — check API key or request structure',
    draft_reply: null,
    gap_summary: 'API error. Full response: ' + JSON.stringify(item).substring(0, 500)
  }, baseFields) }];
}

const rawText = item.content[0].text;

let parsed;
try {
  const clean = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = {
    question_type: 'knowledge_gap',
    answerable: false,
    confidence: 'low',
    raw_persona_tag: 'niche_buyer',
    competition_persona_tag: null,
    theme: 'other',
    marketing_signal: false,
    marketing_signal_reason: null,
    kb_sources_used: [],
    requires_escalation: true,
    escalation_reason: 'Claude response parse error — manual review required',
    draft_reply: null,
    gap_summary: 'Parse error. Raw response: ' + rawText.substring(0, 300)
  };
}

return [{ json: Object.assign(parsed, baseFields) }];
